195: // As we don't need a high precision here, we keep all watchers timeout within a
196: // second in a bucket, and pop up them once at the timeout. To be more specific,
197: // if you set fire time at X, you can get the bookmark within (X-1,X+1) period.
198: type watcherBookmarkTimeBuckets struct {
199: 	// the key of watcherBuckets is the number of seconds since createTime
200: 	watchersBuckets   map[int64][]*cacheWatcher
201: 	createTime        time.Time
202: 	startBucketID     int64
203: 	clock             clock.Clock
204: 	bookmarkFrequency time.Duration
205: }
206: 
207: func newTimeBucketWatchers(clock clock.Clock, bookmarkFrequency time.Duration) *watcherBookmarkTimeBuckets {
208: 	return &watcherBookmarkTimeBuckets{
209: 		watchersBuckets:   make(map[int64][]*cacheWatcher),
210: 		createTime:        clock.Now(),
211: 		startBucketID:     0,
212: 		clock:             clock,
213: 		bookmarkFrequency: bookmarkFrequency,
214: 	}
215: }
216: 
217: // adds a watcher to the bucket, if the deadline is before the start, it will be
218: // added to the first one.
219: func (t *watcherBookmarkTimeBuckets) addWatcherThreadUnsafe(w *cacheWatcher) bool {
220: 	// note that the returned time can be before t.createTime,
221: 	// especially in cases when the nextBookmarkTime method
222: 	// give us the zero value of type Time
223: 	// so buckedID can hold a negative value
224: 	nextTime, ok := w.nextBookmarkTime(t.clock.Now(), t.bookmarkFrequency)
225: 	if !ok {
226: 		return false
227: 	}
228: 	bucketID := int64(nextTime.Sub(t.createTime) / time.Second)
229: 	if bucketID < t.startBucketID {
230: 		bucketID = t.startBucketID
231: 	}
232: 	watchers := t.watchersBuckets[bucketID]
233: 	t.watchersBuckets[bucketID] = append(watchers, w)
234: 	return true
235: }
236: 
237: func (t *watcherBookmarkTimeBuckets) popExpiredWatchersThreadUnsafe() [][]*cacheWatcher {
238: 	currentBucketID := int64(t.clock.Since(t.createTime) / time.Second)
239: 	// There should be one or two elements in almost all cases
240: 	expiredWatchers := make([][]*cacheWatcher, 0, 2)
241: 	for ; t.startBucketID <= currentBucketID; t.startBucketID++ {
242: 		if watchers, ok := t.watchersBuckets[t.startBucketID]; ok {
243: 			delete(t.watchersBuckets, t.startBucketID)
244: 			expiredWatchers = append(expiredWatchers, watchers)
245: 		}
246: 	}
247: 	return expiredWatchers
248: }
